package main

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	grpc_middleware "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	"go.flipt.io/flipt/internal/server/authn/method"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	grpclib "google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression tests the two authentication issues:
// 1. Cookie tokens are not properly extracted from HTTP cookies
// 2. Server-level authentication bypass mechanism exists but may not work properly
func TestRegression(t *testing.T) {
	t.Run("CookieTokenNotExtractedFromHTTPCookies", testCookieTokenNotExtracted)
	t.Run("ServerSkipAuthenticationNotWorking", testServerSkipAuthNotWorking)
}

// testCookieTokenNotExtracted demonstrates that valid client tokens in HTTP cookies
// are not properly extracted and passed through to the gRPC authentication middleware.
func testCookieTokenNotExtracted(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid authentication token
	clientToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	// Test 1: ForwardCookies bug - it uses the wrong metadata key
	t.Run("ForwardCookiesBug", func(t *testing.T) {
		// Create an HTTP request with a valid client token cookie
		req := httptest.NewRequest(http.MethodGet, "/api/test", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// ForwardCookies should extract the cookie and add it to metadata
		md := method.ForwardCookies(context.Background(), req)

		// BUG: The function always sets md["flipt_client_state"] regardless of which
		// cookie key is being processed. This means:
		// 1. If a token cookie is found, it overwrites the state cookie key
		// 2. The actual token cookie is never added to metadata with the correct key
		// 3. The gRPC middleware cannot extract the token from metadata

		// The token should be accessible under "flipt_client_token" key
		tokenValues := md.Get("flipt_client_token")
		if len(tokenValues) > 0 {
			assert.Equal(t, clientToken, tokenValues[0],
				"token should be extracted and available in metadata under correct key")
		} else {
			// BUG: This is the actual problem - the token is not in the right place
			t.Logf("BUG DETECTED: Token cookie not found in metadata under 'flipt_client_token' key")
			t.Logf("Metadata keys: %v", md)
			// The token is incorrectly stored under "flipt_client_state" instead
			stateValues := md.Get("flipt_client_state")
			if len(stateValues) > 0 {
				t.Logf("ERROR: Token was incorrectly stored under 'flipt_client_state' key")
				assert.Fail(t, "ForwardCookies has a bug: token stored under wrong key")
			}
		}
	})

	// Test 2: gRPC middleware cannot extract token from HTTP cookie
	t.Run("GRPCMiddlewareCannotExtractCookieToken", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		// Simulate a gRPC request with the token in an HTTP cookie
		// In a real scenario, the HTTP gateway would use ForwardCookies to convert
		// HTTP cookies to gRPC metadata. However, due to the bug in ForwardCookies,
		// the token is not properly forwarded.

		// Create metadata as if ForwardCookies was called (with the bug)
		md := metadata.MD{
			// ForwardCookies incorrectly puts the token under the state key
			"flipt_client_state": []string{"token_value_here"},
		}

		ctx := metadata.NewIncomingContext(context.Background(), md)
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		// The ClientTokenAuthenticationInterceptor should fail to extract the token
		// because it looks for the token in the wrong place
		_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		// This should fail with ErrUnauthenticated because the token is not found
		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"should fail to authenticate when token is in wrong metadata key")
	})

	// Test 3: Verify that the issue occurs specifically with cookie-based tokens
	t.Run("BearerTokenWorksButCookieDoesNot", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Test 3a: Bearer token in Authorization header works
		t.Run("BearerTokenInHeaderWorks", func(t *testing.T) {
			md := metadata.MD{
				"authorization": []string{"Bearer " + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			assert.NoError(t, err, "bearer token should work")
		})

		// Test 3b: Cookie-based token does not work (the bug)
		t.Run("CookieTokenFails", func(t *testing.T) {
			// Create proper gRPC cookie metadata (grpcgateway-cookie header)
			// This is what gRPC expects for cookies
			md := metadata.MD{
				"grpcgateway-cookie": []string{"flipt_client_token=" + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			// This should theoretically work, but due to issues in the implementation,
			// it might fail. Let's verify the current behavior.
			if err != nil {
				t.Logf("ISSUE: Cookie-based authentication failed: %v", err)
				t.Logf("This suggests that while the infrastructure exists, " +
					"HTTP cookies from browsers are not properly converted to gRPC cookies")
			}
		})
	})
}

// testServerSkipAuthNotWorking verifies that the server skip authentication mechanism
// works correctly when implemented.
func testServerSkipAuthNotWorking(t *testing.T) {
	logger := zaptest.NewLogger(t)

	// Test the SkipsAuthenticationServer interface
	t.Run("SkipsAuthenticationServerInterface", func(t *testing.T) {
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			auth := grpc.GetAuthenticationFrom(ctx)
			assert.Nil(t, auth, "authentication should be nil when skipped")
			return nil, nil
		}

		// Server that skips authentication
		skippingServer := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: skippingServer}

		// Create an interceptor that requires authentication
		interceptor := grpc.AuthenticationRequiredInterceptor(logger)

		// Even without authentication on context, should succeed because server skips auth
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server that skips authentication should bypass the AuthenticationRequiredInterceptor")
	})

	// Test WithServerSkipsAuthentication option
	t.Run("WithServerSkipsAuthenticationOption", func(t *testing.T) {
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Server that does NOT implement SkipsAuthenticationServer
		regularServer := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: regularServer}

		// Create interceptor with the option to skip this specific server
		interceptor := grpc.AuthenticationRequiredInterceptor(
			logger,
			grpc.WithServerSkipsAuthentication(regularServer),
		)

		// Should succeed because the server is in the skip list
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server in WithServerSkipsAuthentication list should bypass authentication")
	})

	// Potential issue: Not all servers may properly implement the skipping mechanism
	t.Run("ServerSkipAuthenticationMayNotBeUsed", func(t *testing.T) {
		// This test documents that while the infrastructure for skipping authentication exists,
		// it may not be applied to all servers that need it.

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// A server that SHOULD skip authentication but doesn't implement the interface
		internalServer := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: internalServer}

		// Without the skip option, authentication is required
		interceptor := grpc.AuthenticationRequiredInterceptor(logger)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		// This WILL fail because the server is not configured to skip authentication
		assert.Equal(t, grpc.ErrUnauthenticated, err,
			"servers not configured to skip authentication will fail if no auth on context")

		t.Logf("POTENTIAL ISSUE: Servers that need to skip authentication must either:")
		t.Logf("  1. Implement SkipsAuthenticationServer interface, or")
		t.Logf("  2. Be registered with WithServerSkipsAuthentication option")
		t.Logf("If not configured, they will require authentication for all requests.")
	})
}

// mockServer implements both SkipsAuthenticationServer and ScopedAuthenticationServer
// for testing purposes.
type mockServer struct {
	skipsAuth           bool
	allowNamespacedAuth bool
}

func (s *mockServer) SkipsAuthentication(ctx context.Context) bool {
	return s.skipsAuth
}

func (s *mockServer) AllowsNamespaceScopedAuthentication(ctx context.Context) bool {
	return s.allowNamespacedAuth
}

