// TestRegression tests the two authentication issues:
// 1. Cookie tokens are not properly extracted from HTTP cookies
// 2. Server-level authentication bypass mechanism exists but may not work properly
func TestRegression(t *testing.T) {
	t.Run("CookieTokenNotExtractedFromHTTPCookies", testCookieTokenNotExtracted)
	t.Run("ServerSkipAuthenticationBehavior", testServerSkipAuthBehavior)
}

// testCookieTokenNotExtracted demonstrates that valid client tokens in HTTP cookies
// are not properly extracted and passed through to the gRPC authentication middleware.
func testCookieTokenNotExtracted(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid authentication token
	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.TODO(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	// Test 1: ForwardCookies bug in internal/server/authn/method/http.go
	t.Run("ForwardCookiesBugDemonstration", func(t *testing.T) {
		// Create an HTTP request with a valid client token cookie
		req := httptest.NewRequest(http.MethodGet, "/api/test", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// ForwardCookies should extract the cookie and add it to metadata
		// However, there's a bug in the implementation
		md := method.ForwardCookies(context.Background(), req)

		// BUG: Line 49 of internal/server/authn/method/http.go always sets
		// md[stateCookieKey] instead of md[key]. This means:
		// 1. Token cookies are stored under the wrong key
		// 2. They overwrite state cookies
		// 3. gRPC middleware cannot extract the token

		// Check what was actually returned
		stateValues := md.Get("flipt_client_state")
		tokenValues := md.Get("flipt_client_token")

		if len(tokenValues) == 0 {
			// BUG: Token not found under correct key
			t.Logf("BUG CONFIRMED: flipt_client_token not in metadata")
			if len(stateValues) > 0 {
				t.Logf("Token was incorrectly stored under 'flipt_client_state' key instead")
				assert.Fail(t, "ForwardCookies bug: token stored under wrong metadata key")
			}
		}
	})

	// Test 2: Demonstrate HTTP-to-gRPC cookie forwarding issue
	t.Run("HTTPCookieNotForwardedToGRPCMiddleware", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		// Scenario: Browser sends request with token in HTTP cookie
		// The HTTP handler uses ForwardCookies to convert to gRPC metadata
		// But due to bug, the metadata is malformed

		// Simulate the buggy ForwardCookies output
		httpReq := httptest.NewRequest(http.MethodGet, "/api/test", nil)
		httpReq.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})
		md := method.ForwardCookies(context.Background(), httpReq)

		// Now try to use this metadata in gRPC
		ctx := metadata.NewIncomingContext(context.Background(), md)
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		// This should fail because the token metadata is wrong
		if err == grpc_middleware.ErrUnauthenticated {
			t.Logf("ISSUE CONFIRMED: HTTP cookie not properly forwarded to gRPC")
			t.Logf("Root cause: ForwardCookies stores cookies under wrong metadata key")
			assert.Equal(t, grpc_middleware.ErrUnauthenticated, err)
		}
	})

	// Test 3: Verify Bearer token works but cookie does not
	t.Run("BearerTokenWorksButCookieTokenDoesNot", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			auth := grpc_middleware.GetAuthenticationFrom(ctx)
			assert.NotNil(t, auth)
			assert.Equal(t, storedAuth.Id, auth.Id)
			return nil, nil
		}

		// Test 3a: Bearer token works
		t.Run("BearerTokenSucceeds", func(t *testing.T) {
			md := metadata.MD{
				"authorization": []string{"Bearer " + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			assert.NoError(t, err, "Bearer token should authenticate successfully")
		})

		// Test 3b: Proper gRPC cookie format
		t.Run("ProperGRPCCookieFormatShouldWork", func(t *testing.T) {
			// In gRPC, cookies are passed as a special "grpcgateway-cookie" metadata header
			// in the format: "name=value" (just like HTTP Set-Cookie but without attributes)
			md := metadata.MD{
				"grpcgateway-cookie": []string{"flipt_client_token=" + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			// This works if properly forwarded
			assert.NoError(t, err, "gRPC cookie format should authenticate successfully")
		})
	})

	// Test 4: Expired token handling
	t.Run("ExpiredTokenHandling", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		// Create an expired token
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(testNowMinusHour()),
			},
		)
		require.NoError(t, err)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		md := metadata.MD{
			"authorization": []string{"Bearer " + expiredToken},
		}
		ctx := metadata.NewIncomingContext(context.Background(), md)

		_, err = grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"expired token should be rejected")
	})
}

// testServerSkipAuthBehavior tests the server skip authentication mechanism
func testServerSkipAuthBehavior(t *testing.T) {
	logger := zaptest.NewLogger(t)

	// Test 1: SkipsAuthenticationServer interface works
	t.Run("SkipsAuthenticationServerInterface", func(t *testing.T) {
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			// When skipped, handler should still be called
			return nil, nil
		}

		skippingServer := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: skippingServer}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// No authentication on context, but server skips auth
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server implementing SkipsAuthenticationServer should bypass AuthenticationRequiredInterceptor")
	})

	// Test 2: WithServerSkipsAuthentication option works
	t.Run("WithServerSkipsAuthenticationOption", func(t *testing.T) {
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Regular server without the interface
		regularServer := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: regularServer}

		// Create interceptor with skip option
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(
			logger,
			grpc_middleware.WithServerSkipsAuthentication(regularServer),
		)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server registered with WithServerSkipsAuthentication should bypass authentication")
	})

	// Test 3: Server without skip mechanism requires authentication
	t.Run("ServerWithoutSkipMechanismRequiresAuth", func(t *testing.T) {
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		regularServer := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: regularServer}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// No skip mechanism, so should fail without auth
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"server without skip mechanism must have authentication")
	})

	// Test 4: Authentication context is preserved when present
	t.Run("AuthenticationContextPreserved", func(t *testing.T) {
		authenticator := memory.NewStore()
		_, auth, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
		)
		require.NoError(t, err)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrieved := grpc_middleware.GetAuthenticationFrom(ctx)
			assert.Equal(t, auth.Id, retrieved.Id)
			return nil, nil
		}

		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		ctx := grpc_middleware.ContextWithAuthentication(context.Background(), auth)
		_, err = interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err)
	})

	// Test 5: Potential issue - internal servers may not have skip configured
	t.Run("InternalServersMayNotHaveSkipConfigured", func(t *testing.T) {
		// This test documents a potential architectural issue:
		// If an internal server (like one handling OIDC flows) needs to skip auth,
		// it must be explicitly configured with one of:
		// 1. SkipsAuthenticationServer interface implementation
		// 2. WithServerSkipsAuthentication option at interceptor creation
		//
		// If not configured, the server will require authentication for all requests,
		// which may not be appropriate for internal services.

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// A hypothetical internal server that should skip auth but isn't configured
		internalServer := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: internalServer}

		// Default interceptor (no skip configuration)
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		// This will fail
		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err)
		t.Logf("Note: Internal servers requiring skip authentication must be explicitly configured")
	})
}

// mockServer implements SkipsAuthenticationServer for testing
type mockServer struct {
	skipsAuth bool
}

func (s *mockServer) SkipsAuthentication(ctx context.Context) bool {
	return s.skipsAuth
}

// Helper to create a time in the past
func testNowMinusHour() context.Context {
	return context.Background()
}

