package main

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	grpc_middleware "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	"go.flipt.io/flipt/internal/server/authn/method"
	"go.flipt.io/flipt/internal/storage/authn"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	grpclib "google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression tests two authentication issues in Flipt:
// 1. Cookie tokens are not properly extracted from HTTP cookies
// 2. Server skip authentication mechanism validation
func TestRegression(t *testing.T) {
	t.Run("Issue1_CookieTokenExtractionBug", TestCookieTokenBug)
	t.Run("Issue2_ServerSkipAuthMechanism", TestServerSkipAuth)
}

// TestCookieTokenBug demonstrates the cookie extraction bug in ForwardCookies
// Location: internal/server/authn/method/http.go, lines 45-54
func TestCookieTokenBug(t *testing.T) {
	// Create a valid authentication token for testing
	authenticator := memory.NewStore()
	clientToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	t.Run("ForwardCookiesBugBehavior", func(t *testing.T) {
		// BUG LOCATION: internal/server/authn/method/http.go:49
		// Current code:
		//   for _, key := range []string{stateCookieKey, tokenCookieKey} {
		//       if cookie, err := req.Cookie(key); err == nil {
		//           md[stateCookieKey] = []string{cookie.Value}  // BUG: Always uses stateCookieKey
		//       }
		//   }
		// Should be:
		//   md[key] = []string{cookie.Value}

		// Create HTTP request with a token cookie (as a browser would send)
		req := httptest.NewRequest(http.MethodGet, "/api/evaluate", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// Call ForwardCookies to convert HTTP cookies to gRPC metadata
		md := method.ForwardCookies(context.Background(), req)

		// Expected: Token should be in metadata under key "flipt_client_token"
		// Actual (with bug): Token is stored under "flipt_client_state" key instead
		tokenValues := md.Get("flipt_client_token")
		stateValues := md.Get("flipt_client_state")

		// This assertion will fail, confirming the bug
		if len(tokenValues) == 0 && len(stateValues) > 0 {
			t.Logf("BUG CONFIRMED: Token stored under wrong key")
			t.Logf("Expected md[\"flipt_client_token\"], got md[\"flipt_client_state\"]")
			assert.Fail(t, "ForwardCookies stores cookies under wrong metadata key")
		}
	})

	t.Run("HTTPCookieNotForwardedToGRPC", func(t *testing.T) {
		// Scenario: Browser sends request with token in HTTP Set-Cookie header
		// HTTP gateway should convert to gRPC metadata using ForwardCookies
		// Due to bug, gRPC middleware cannot find the token

		logger := zaptest.NewLogger(t)
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Create HTTP request with cookie
		httpReq := httptest.NewRequest(http.MethodPost, "/api/evaluate", nil)
		httpReq.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// ForwardCookies returns malformed metadata due to bug
		md := method.ForwardCookies(context.Background(), httpReq)
		ctx := metadata.NewIncomingContext(context.Background(), md)
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		// Try to authenticate with the malformed metadata
		_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		// Should fail because token is under wrong key
		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"HTTP cookie not properly forwarded due to ForwardCookies bug")
	})

	t.Run("BearerTokenWorksButHTTPCookieDoesNot", func(t *testing.T) {
		logger := zaptest.NewLogger(t)
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Test 1: Bearer token works (this works correctly)
		t.Run("BearerTokenWorks", func(t *testing.T) {
			md := metadata.MD{
				"authorization": []string{"Bearer " + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			assert.NoError(t, err,
				"bearer token should authenticate successfully")
		})

		// Test 2: HTTP cookie requires gRPC cookie format (grpcgateway-cookie)
		t.Run("GRPCCookieFormatWorks", func(t *testing.T) {
			// gRPC cookies are passed in special "grpcgateway-cookie" header
			// In format: "name=value; name=value; ..."
			md := metadata.MD{
				"grpcgateway-cookie": []string{"flipt_client_token=" + clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			// This works IF the HTTP gateway properly converts HTTP cookies to grpcgateway-cookie
			// But ForwardCookies bug prevents this conversion
			assert.NoError(t, err,
				"gRPC cookie format should work when properly forwarded")
		})

		// Test 3: Browser cookies cannot bypass Bearer token requirement
		t.Run("BrowserCookieBypassFails", func(t *testing.T) {
			// A browser sends the cookie in HTTP Set-Cookie header
			// But the authentication middleware only checks Authorization header
			// and grpcgateway-cookie gRPC metadata

			md := metadata.MD{
				// Browser cookie is not being forwarded properly
				"flipt_client_token": []string{clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			// Fails because token is under wrong key for gRPC
			assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
				"Browser cookies not accepted due to missing ForwardCookies implementation")
		})
	})

	t.Run("ExpiredTokenRejected", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		// Create expired token
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-1 * time.Hour)),
			},
		)
		require.NoError(t, err)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		md := metadata.MD{
			"authorization": []string{"Bearer " + expiredToken},
		}
		ctx := metadata.NewIncomingContext(context.Background(), md)

		_, err = grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"expired token must be rejected")
	})
}

// TestServerSkipAuth tests the server skip authentication mechanism
func TestServerSkipAuth(t *testing.T) {
	logger := zaptest.NewLogger(t)

	t.Run("SkipsAuthenticationInterfaceWorks", func(t *testing.T) {
		// The SkipsAuthenticationServer interface allows servers to opt out
		// Location: internal/server/authn/middleware/grpc/middleware.go:112-115

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Server that implements SkipsAuthenticationServer
		server := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// Should NOT require authentication
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server implementing SkipsAuthenticationServer should bypass auth requirement")
	})

	t.Run("WithServerSkipsAuthenticationOption", func(t *testing.T) {
		// The WithServerSkipsAuthentication option allows registering servers to skip auth
		// Location: internal/server/authn/middleware/grpc/middleware.go:97-105

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		server := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: server}

		// Register server to skip authentication
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(
			logger,
			grpc_middleware.WithServerSkipsAuthentication(server),
		)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server in skip list should bypass authentication")
	})

	t.Run("ServerWithoutSkipRequiresAuth", func(t *testing.T) {
		// Potential issue: Servers not configured to skip will require authentication
		// This could be problematic for internal services like OIDC handlers

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Server without skip configuration
		server := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		// Will fail if not configured
		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"server without skip configuration requires authentication")

		t.Logf("NOTE: Internal servers must be explicitly configured to skip authentication")
		t.Logf("This is done via SkipsAuthenticationServer interface or WithServerSkipsAuthentication option")
	})

	t.Run("SkipAuthPreservesAuthContext", func(t *testing.T) {
		// When a server skips authentication, it doesn't populate auth context
		// This is expected behavior

		authenticator := memory.NewStore()
		_, auth, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
		)
		require.NoError(t, err)

		// Handler checks for authentication context
		handlerCalled := false
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			handlerCalled = true
			retrieved := grpc_middleware.GetAuthenticationFrom(ctx)
			// When skipped, auth context may be nil
			return nil, nil
		}

		server := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// Call interceptor
		ctx := context.Background()
		_, err = interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err)
		assert.True(t, handlerCalled, "handler should be called even when skipping auth")
	})
}

// mockServer implements SkipsAuthenticationServer interface for testing
type mockServer struct {
	skipsAuth bool
}

func (s *mockServer) SkipsAuthentication(ctx context.Context) bool {
	return s.skipsAuth
}
